css: @import url('https://cdn.jsdelivr.net/npm/tailwindcss@2.2.19/dist/tailwind.min.css');

#notification {
    animation: pulse 1.5s infinite;
}

@keyframes pulse {
    0% {
        transform: scale(1);
    }
    50% {
        transform: scale(1.1);
        opacity: 0.8;
    }
    100% {
        transform: scale(1);
    }
}

#notification:hover {
    transform: scale(1.2);
    background-color: #33cc33 !important;
}

#notification:active {
    background-color: #00ff00 !important;
    transform: scale(1.1);
}

#show-notification {
    position: absolute;
    top: 20px;
    right: 20px;
}

js: // Import required modules
const notification = document.getElementById('notification');
const showNotificationButton = document.getElementById('show-notification');

// Define a function to show the notification
function showNotification() {
    notification.classList.remove('hidden');
}

// Define a function to hide the notification
function hideNotification() {
    notification.classList.add('hidden');
}

// Add an event listener to the show notification button
showNotificationButton.addEventListener('click', () => {
    showNotification();
    setTimeout(hideNotification, 5000);
});
